import pandas as pd
import matplotlib.pyplot as plt

# Load the data generated by the bash script
df = pd.read_csv("results.csv")
configs = df['Config'].unique()

max_speedup_overall = 0
best_config = ""
best_threads = 0

print("=========================================")
print("      PERFORMANCE ANALYSIS REPORT        ")
print("=========================================")

# ---------------------------------------------------------
# 1. Execution Time Plot (Now starting at 1 core)
# ---------------------------------------------------------
plt.figure(figsize=(10, 6))
for config in configs:
    serial_time = df[(df['Config'] == config) & (df['Mode'] == 'Serial')]['Time'].values[0]
    par_data = df[(df['Config'] == config) & (df['Mode'] == 'Parallel')]
    
    # Stitch 1-core serial data to the front of parallel data
    threads = [1] + list(par_data['Threads'].values)
    times = [serial_time] + list(par_data['Time'].values)
    
    plt.plot(threads, times, marker='o', label=config)

plt.title("Execution Time vs. Number of Cores")
plt.xlabel("Number of Cores")
plt.ylabel("Execution Time (Seconds)")
plt.xticks([1, 2, 4, 6, 8, 10, 12, 14, 16])
plt.legend()
plt.grid(True)
plt.savefig("time_vs_cores.png")
plt.clf()

# ---------------------------------------------------------
# 2. Speedup Plot (Now starting at 1 core)
# ---------------------------------------------------------
plt.figure(figsize=(10, 6))
for config in configs:
    serial_time = df[(df['Config'] == config) & (df['Mode'] == 'Serial')]['Time'].values[0]
    par_data = df[(df['Config'] == config) & (df['Mode'] == 'Parallel')]
    
    par_speedups = serial_time / par_data['Time'].values
    par_efficiencies = par_speedups / par_data['Threads'].values
    
    # Stitch 1-core data (Speedup = 1.0) to the front
    threads = [1] + list(par_data['Threads'].values)
    speedups = [1.0] + list(par_speedups)
    
    # Track overall maximum speedup for the report
    local_max_speedup = max(speedups)
    if local_max_speedup > max_speedup_overall:
        max_speedup_overall = local_max_speedup
        best_config = config
        best_threads = threads[speedups.index(local_max_speedup)]
        
    plt.plot(threads, speedups, marker='s', label=config)
    
    # Print terminal output for the report table
    print(f"\nConfiguration: {config} (Serial Time: {serial_time:.4f} s)")
    print(f"  Cores:  1 | Speedup:  1.00x | Efficiency: 100.0%")
    for t, s, e in zip(par_data['Threads'], par_speedups, par_efficiencies):
        print(f"  Cores: {t:2d} | Speedup: {s:5.2f}x | Efficiency: {e*100:5.1f}%")

plt.plot([1, 16], [1, 16], 'k--', label="Ideal Speedup")
plt.title("Speedup vs. Number of Cores")
plt.xlabel("Number of Cores")
plt.ylabel("Speedup")
plt.xticks([1, 2, 4, 6, 8, 10, 12, 14, 16])
plt.legend()
plt.grid(True)
plt.savefig("speedup_vs_cores.png")
plt.clf()

# ---------------------------------------------------------
# 3. Parallel Efficiency Plot (Now starting at 1 core)
# ---------------------------------------------------------
plt.figure(figsize=(10, 6))
for config in configs:
    serial_time = df[(df['Config'] == config) & (df['Mode'] == 'Serial')]['Time'].values[0]
    par_data = df[(df['Config'] == config) & (df['Mode'] == 'Parallel')]
    
    par_speedups = serial_time / par_data['Time'].values
    par_efficiencies = par_speedups / par_data['Threads'].values
    
    # Stitch 1-core data (Efficiency = 100%) to the front
    threads = [1] + list(par_data['Threads'].values)
    efficiencies = [100.0] + list(par_efficiencies * 100)
    
    plt.plot(threads, efficiencies, marker='^', label=config)

plt.axhline(y=100, color='k', linestyle='--', label="Ideal Efficiency (100%)")
plt.title("Parallel Efficiency vs. Number of Cores")
plt.xlabel("Number of Cores")
plt.ylabel("Parallel Efficiency (%)")
plt.xticks([1, 2, 4, 6, 8, 10, 12, 14, 16])
plt.legend()
plt.grid(True)
plt.savefig("efficiency_vs_cores.png")

print("\n=========================================")
print("          MAXIMUM SPEEDUP (Req 5)        ")
print("=========================================")
print(f"Maximum Speedup Achieved: {max_speedup_overall:.2f}x")
print(f"Achieved on Config: {best_config} using {best_threads} Cores")
print("=========================================")
print("Plots generated: time_vs_cores.png, speedup_vs_cores.png, efficiency_vs_cores.png")
